class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int n = s.size(), m = p.size();
        int star[2];
        int cnt = 0;
        for (int i = 0; i < m; i++) {
            if (p[i] == '*') {
                star[cnt++] = i;
            }
        }

        int ans = n + 1;
        for (int i = 0; i <= n - (m - star[1] - 1); i++) {
            int l = i, r = i + m - 1;
            int pL = 0, pR = m - 1;
            bool match = true;
            while (l <= r) {
                if (pL == star[0] || pR == star[1]) {
                    if (pL == star[0]) {
                        pL++;
                    }
                    if (pR == star[1]) {
                        pR--;
                    }
                    continue;
                }
                if (s[l] != p[pL]) {
                    match = false;
                    break;
                }
                l++;
                pL++;
            }
            if (match) {
                int len = r - i + 1;
                ans = min(ans, len);
            }
        }
        return ans > n ? -1 : ans;
    }
};
```
